const listPendingMetadataReviewInbox = `-- name: ListPendingMetadataReviewInbox :many
SELECT
    mr.id,
    mr.series_id,
    mr.provider,
    mr.source_url,
    mr.source_id,
    mr.source_query,
    mr.summary,
    mr.confidence,
    mr.status,
    mr.raw_payload,
    mr.created_at,
    mr.updated_at,
    mr.applied_at,
    mr.rejected_at,
    s.library_id,
    l.name as library_name,
    s.name as series_name,
    COALESCE(s.title, '') as series_title,
    CAST(COALESCE((
        SELECT b.id
        FROM books b
        WHERE b.series_id = s.id AND b.cover_path IS NOT NULL AND b.cover_path != ''
        ORDER BY b.sort_number, b.name
        LIMIT 1
    ), 0) AS INTEGER) as cover_book_id,
    CAST((SELECT COUNT(*) FROM metadata_review_fields f WHERE f.review_id = mr.id) AS INTEGER) as field_count,
    CAST((SELECT COUNT(*) FROM metadata_review_fields f WHERE f.review_id = mr.id AND f.locked = TRUE) AS INTEGER) as locked_field_count
FROM metadata_reviews mr
JOIN series s ON s.id = mr.series_id
JOIN libraries l ON l.id = s.library_id
WHERE mr.status = 'pending'
  AND (CAST(?1 AS INTEGER) = 0 OR s.library_id = CAST(?1 AS INTEGER))
  AND (CAST(?2 AS TEXT) = '' OR lower(mr.provider) = lower(CAST(?2 AS TEXT)))
  AND (
    CAST(?3 AS TEXT) = ''
    OR instr(lower(s.name), lower(CAST(?3 AS TEXT))) > 0
    OR instr(lower(COALESCE(s.title, '')), lower(CAST(?3 AS TEXT))) > 0
    OR instr(lower(mr.source_query), lower(CAST(?3 AS TEXT))) > 0
  )
ORDER BY mr.confidence ASC, mr.created_at ASC
LIMIT ?5 OFFSET ?4
`

